import Foundation

enum InstallableKind: Equatable {
    case diskImage
    case appBundle
    case zipArchive

    init?(url: URL) {
        switch url.pathExtension.lowercased() {
        case "dmg":
            self = .diskImage
        case "app":
            self = .appBundle
        case "zip":
            self = .zipArchive
        default:
            return nil
        }
    }
}

